import { useState, useRef } from "react";

// ─── HELPER: Nome Científico (preserva grafia no modo AEE) ────────────────────
const NC = ({children}) => <span className="nc">{children}</span>;

const MAPA_BIOMAS_B64="data:image/png;base64,";


// ─── ESTILOS GLOBAIS ──────────────────────────────────────────────────────────
const GlobalStyles = () => (
  <style>{`
    @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;0,900;1,400&family=Lato:wght@300;400;700;900&family=Crimson+Pro:ital,wght@0,300;0,400;0,600;1,300;1,400&display=swap');
    *, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }
    :root {
      --verde-floresta:#1a3a2a; --verde-medio:#2d5a3d; --verde-musgo:#4a7c59;
      --verde-folha:#6b9e78;    --verde-claro:#a8c5a0; --terra:#8b5e3c;
      --terra-claro:#c4956a;    --ocre:#d4a853;        --creme:#f5f0e8;
      --pergaminho:#ede8d8;     --escuro:#0f1f16;
      --acerto:#2d7a47; --erro:#8b2d2d;
      --acerto-bg:rgba(45,122,71,.18); --erro-bg:rgba(139,45,45,.18);
    }
    body{ background:#1a3a2a; font-family:'Lato',sans-serif; }
    .codex-root{ width:100%; min-height:100vh; background:var(--verde-floresta);
      display:flex; align-items:center; justify-content:center;
      font-family:'Lato',sans-serif; overflow-x:hidden; }

    @keyframes fadeInUp  { from{opacity:0;transform:translateY(24px)} to{opacity:1;transform:translateY(0)} }
    @keyframes fadeIn    { from{opacity:0} to{opacity:1} }
    @keyframes floatLeaf { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-12px) rotate(3deg)} }
    @keyframes shimmer   { 0%{background-position:-200% center} 100%{background-position:200% center} }
    @keyframes pulseGlow { 0%,100%{box-shadow:0 0 20px rgba(107,158,120,.3)} 50%{box-shadow:0 0 40px rgba(107,158,120,.6)} }
    @keyframes popIn     { 0%{transform:scale(.85);opacity:0} 60%{transform:scale(1.04)} 100%{transform:scale(1);opacity:1} }
    @keyframes slideDown { from{opacity:0;transform:translateY(-14px)} to{opacity:1;transform:translateY(0)} }
    @keyframes aeeAcertoGlow {
      0%   { box-shadow: 0 0 0 0 rgba(45,200,100,.0); transform: scale(1); }
      25%  { box-shadow: 0 0 0 12px rgba(45,200,100,.55); transform: scale(1.025); }
      55%  { box-shadow: 0 0 0 20px rgba(45,200,100,.25); transform: scale(1.015); }
      80%  { box-shadow: 0 0 0 8px rgba(45,200,100,.1); }
      100% { box-shadow: 0 0 0 0 rgba(45,200,100,.0); transform: scale(1); }
    }
    @keyframes aeeAcertoEstrela {
      0%   { transform: scale(0) rotate(-20deg); opacity:0; }
      40%  { transform: scale(1.4) rotate(10deg); opacity:1; }
      65%  { transform: scale(0.9) rotate(-5deg); }
      100% { transform: scale(1) rotate(0deg); opacity:1; }
    }
    @keyframes aeeIconePulso {
      0%,100% { transform: scale(1); }
      40%     { transform: scale(1.5); }
      70%     { transform: scale(0.9); }
    }

    .anim-1{animation:fadeInUp .6s ease both}
    .anim-2{animation:fadeInUp .6s .12s ease both}
    .anim-3{animation:fadeInUp .6s .24s ease both}
    .anim-4{animation:fadeInUp .6s .36s ease both}
    .anim-5{animation:fadeInUp .6s .48s ease both}
    .anim-6{animation:fadeInUp .6s .60s ease both}
    .anim-7{animation:fadeInUp .6s .72s ease both}

    .leaf-deco{position:absolute;opacity:.12;animation:floatLeaf 6s ease-in-out infinite;z-index:1;pointer-events:none}
    .leaf-deco.l1{top:5%;left:3%;font-size:80px;animation-delay:0s}
    .leaf-deco.l2{top:15%;right:5%;font-size:60px;animation-delay:1.5s}
    .leaf-deco.l3{bottom:20%;left:5%;font-size:100px;animation-delay:3s}
    .leaf-deco.l4{bottom:10%;right:3%;font-size:70px;animation-delay:2s}
    .leaf-deco.l5{top:45%;left:1%;font-size:50px;animation-delay:4s}

    /* TELA ABERTURA */
    .tela-abertura{width:100%;min-height:100vh;position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px 24px;overflow:hidden}
    .bg-pattern{position:absolute;inset:0;background:radial-gradient(ellipse at 20% 80%,rgba(45,90,61,.6) 0%,transparent 50%),radial-gradient(ellipse at 80% 20%,rgba(74,124,89,.4) 0%,transparent 45%),linear-gradient(160deg,#0f1f16 0%,#1a3a2a 40%,#0d2219 100%);z-index:0}
    .abertura-content{position:relative;z-index:2;width:100%;max-width:720px;display:flex;flex-direction:column;align-items:center;gap:28px;text-align:center}
    .badge-curricular{display:flex;flex-wrap:wrap;gap:8px;justify-content:center}
    .badge-item{background:rgba(168,197,160,.15);border:1px solid rgba(168,197,160,.4);color:var(--verde-claro);font-size:11px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;padding:5px 12px;border-radius:20px}
    .titulo-eyebrow{font-size:12px;font-weight:700;letter-spacing:.22em;text-transform:uppercase;color:var(--ocre)}
    .titulo-principal{font-family:'Playfair Display',serif;font-size:clamp(38px,7vw,68px);font-weight:900;line-height:1;color:var(--creme);text-shadow:0 4px 24px rgba(0,0,0,.5)}
    .titulo-sub{font-family:'Crimson Pro',serif;font-size:clamp(16px,3vw,22px);font-style:italic;font-weight:300;color:var(--verde-claro);margin-top:4px}
    .divisor-bot{display:flex;align-items:center;gap:12px;width:100%;max-width:400px}
    .divisor-linha{flex:1;height:1px;background:linear-gradient(90deg,transparent,rgba(168,197,160,.5),transparent)}
    .sinopse{font-family:'Crimson Pro',serif;font-size:clamp(15px,2.5vw,19px);line-height:1.75;color:rgba(245,240,232,.88);max-width:600px;padding:24px 28px 24px 44px;border-left:3px solid var(--verde-musgo);border-right:3px solid var(--verde-musgo);background:rgba(255,255,255,.04);border-radius:4px;text-align:left;position:relative}
    .sinopse::before{content:'"';font-family:'Playfair Display',serif;font-size:80px;color:var(--verde-musgo);opacity:.4;position:absolute;top:-10px;left:12px;line-height:1}
    .btn-iniciar{display:inline-flex;align-items:center;gap:12px;padding:18px 44px;background:linear-gradient(135deg,var(--verde-medio),var(--verde-musgo));color:var(--creme);border:none;border-radius:4px;font-size:16px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;cursor:pointer;position:relative;overflow:hidden;transition:transform .2s,box-shadow .2s;animation:pulseGlow 3s ease-in-out infinite}
    .btn-iniciar::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,transparent 40%,rgba(255,255,255,.1) 50%,transparent 60%);background-size:200% auto;animation:shimmer 3s linear infinite}
    .btn-iniciar:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(45,90,61,.6)}
    .rodape-abertura{font-size:12px;font-weight:300;color:rgba(168,197,160,.5);letter-spacing:.06em}

    /* TELA APRENDIZAGENS */
    .tela-aprendizagens{width:100%;min-height:100vh;position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px 24px;overflow:hidden}
    .bg-aprend{position:absolute;inset:0;background:radial-gradient(ellipse at 10% 90%,rgba(139,94,60,.25) 0%,transparent 40%),linear-gradient(170deg,#0f1f16,#152d1e,#0d2219);z-index:0}
    .aprend-card{position:relative;z-index:2;width:100%;max-width:680px;background:rgba(245,240,232,.05);border:1px solid rgba(168,197,160,.2);border-radius:8px;padding:44px;backdrop-filter:blur(10px)}
    .aprend-header{display:flex;flex-direction:column;gap:6px;margin-bottom:32px}
    .aprend-label{font-size:11px;font-weight:700;letter-spacing:.2em;text-transform:uppercase;color:var(--ocre)}
    .aprend-titulo{font-family:'Playfair Display',serif;font-size:clamp(24px,4vw,32px);font-weight:700;color:var(--creme)}
    .aprend-lista{list-style:none;display:flex;flex-direction:column;gap:12px;margin-bottom:36px}
    .aprend-item{display:flex;align-items:flex-start;gap:14px;padding:14px 16px;background:rgba(255,255,255,.04);border-left:3px solid var(--verde-musgo);border-radius:0 4px 4px 0;transition:background .2s,border-color .2s}
    .aprend-item:hover{background:rgba(107,158,120,.1);border-color:var(--verde-folha)}
    .aprend-icone{color:var(--verde-folha);font-size:18px;flex-shrink:0;margin-top:1px}
    .aprend-texto{font-family:'Crimson Pro',serif;font-size:17px;line-height:1.5;color:rgba(245,240,232,.9)}
    .divisor-sutil{width:100%;height:1px;background:linear-gradient(90deg,transparent,rgba(168,197,160,.3),transparent);margin:24px 0}
    .nome-label{font-size:12px;font-weight:700;letter-spacing:.15em;text-transform:uppercase;color:var(--verde-claro);display:block;margin-bottom:8px}
    .nome-wrapper{position:relative}
    .nome-input{width:100%;padding:16px 20px 16px 48px;background:rgba(255,255,255,.07);border:1.5px solid rgba(168,197,160,.3);border-radius:4px;color:var(--creme);font-family:'Crimson Pro',serif;font-size:18px;outline:none;transition:border-color .2s,background .2s}
    .nome-input::placeholder{color:rgba(168,197,160,.4);font-style:italic}
    .nome-input:focus{border-color:var(--verde-folha);background:rgba(107,158,120,.08)}
    .nome-icon{position:absolute;left:16px;top:50%;transform:translateY(-50%);font-size:20px;color:var(--verde-musgo);pointer-events:none}
    .btn-entrar{width:100%;margin-top:20px;padding:18px;background:linear-gradient(135deg,var(--terra),var(--ocre));color:var(--escuro);border:none;border-radius:4px;font-size:15px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;cursor:pointer;transition:transform .2s,box-shadow .2s,opacity .2s;display:flex;align-items:center;justify-content:center;gap:10px}
    .btn-entrar:hover:not(:disabled){transform:translateY(-2px);box-shadow:0 8px 28px rgba(212,168,83,.4)}
    .btn-entrar:disabled{opacity:.4;cursor:not-allowed}

    /* TELA MISSAO */
    .tela-missao{width:100%;min-height:100vh;position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px 24px;overflow:hidden}
    .bg-missao{position:absolute;inset:0;background:radial-gradient(ellipse at 50% 0%,rgba(74,124,89,.4) 0%,transparent 50%),linear-gradient(180deg,#0d2219,#1a3a2a,#0a1a10);z-index:0}
    .bio-grid{position:absolute;inset:0;z-index:1;opacity:.06;background-image:repeating-linear-gradient(0deg,transparent,transparent 59px,rgba(168,197,160,.5) 60px),repeating-linear-gradient(90deg,transparent,transparent 59px,rgba(168,197,160,.5) 60px);pointer-events:none}
    .missao-content{position:relative;z-index:2;width:100%;max-width:620px;display:flex;flex-direction:column;align-items:center;gap:28px;text-align:center}
    .missao-emblema{width:100px;height:100px;border:2px solid rgba(168,197,160,.4);border-radius:50%;display:flex;align-items:center;justify-content:center;background:rgba(45,90,61,.3);font-size:44px;animation:pulseGlow 3s ease-in-out infinite}
    .missao-linha1{font-size:13px;font-weight:700;letter-spacing:.2em;text-transform:uppercase;color:var(--verde-folha)}
    .missao-nome{font-family:'Playfair Display',serif;font-size:clamp(28px,5vw,46px);font-weight:900;color:var(--creme)}
    .missao-texto{font-family:'Crimson Pro',serif;font-size:clamp(15px,2.5vw,18px);font-weight:300;line-height:1.8;color:rgba(245,240,232,.8);max-width:520px}
    .dra-panel{display:flex;align-items:flex-start;gap:16px;background:rgba(255,255,255,.04);border:1px solid rgba(168,197,160,.2);border-radius:6px;padding:20px 22px;text-align:left;width:100%}
    .dra-avatar{font-size:32px;flex-shrink:0;background:rgba(45,90,61,.4);width:52px;height:52px;border-radius:50%;display:flex;align-items:center;justify-content:center;border:1px solid rgba(107,158,120,.4)}
    .dra-nome-tag{font-size:12px;font-weight:700;color:var(--verde-folha);letter-spacing:.04em;display:block;margin-bottom:4px}
    .dra-fala{font-family:'Crimson Pro',serif;font-size:15px;font-style:italic;line-height:1.6;color:rgba(245,240,232,.8)}
    .biomas-row{display:flex;flex-wrap:wrap;gap:8px;justify-content:center}
    .bioma-badge{display:flex;align-items:center;gap:6px;padding:6px 14px;background:rgba(255,255,255,.05);border:1px solid rgba(168,197,160,.25);border-radius:20px;font-size:12px;font-weight:700;letter-spacing:.06em;color:rgba(245,240,232,.7)}
    .btn-missao{width:100%;padding:20px;background:linear-gradient(135deg,#1e5c35,#2d7a47,#3a9456);color:var(--creme);border:none;border-radius:4px;font-size:17px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;cursor:pointer;transition:transform .2s,box-shadow .2s;display:flex;align-items:center;justify-content:center;gap:12px;position:relative;overflow:hidden}
    .btn-missao::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,transparent 40%,rgba(255,255,255,.08) 50%,transparent 60%);background-size:200% auto;animation:shimmer 2.5s linear infinite}
    .btn-missao:hover{transform:translateY(-3px);box-shadow:0 14px 40px rgba(30,92,53,.6)}
    .rodape-missao{font-size:11px;font-weight:300;color:rgba(168,197,160,.4);letter-spacing:.06em;line-height:1.8;text-align:center}
    .rodape-missao strong{font-weight:700;color:rgba(168,197,160,.6)}

    /* JOGO */
    .jogo-wrapper{width:100%;min-height:100vh;display:flex;flex-direction:column;background:linear-gradient(170deg,#0d2219 0%,#152d1e 40%,#0a1a10 100%)}
    .hud{width:100%;padding:12px 20px;background:rgba(10,26,16,.85);border-bottom:1px solid rgba(168,197,160,.15);display:flex;align-items:center;gap:12px;flex-wrap:wrap;backdrop-filter:blur(8px);position:sticky;top:0;z-index:50}
    .hud-fase{font-size:12px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:var(--verde-folha);white-space:nowrap}
    .hud-barra-wrap{flex:1;min-width:60px;height:6px;background:rgba(255,255,255,.1);border-radius:3px;overflow:hidden}
    .hud-barra-fill{height:100%;background:linear-gradient(90deg,var(--verde-musgo),var(--ocre));border-radius:3px;transition:width .6s ease}
    .hud-bioma{font-size:11px;color:rgba(168,197,160,.6);white-space:nowrap}
    .hud-pontos{font-size:13px;font-weight:700;color:var(--ocre);white-space:nowrap;margin-left:auto}
    .fase-content{flex:1;padding:20px;display:flex;flex-direction:column;gap:18px;max-width:780px;margin:0 auto;width:100%}

    /* Diálogo */
    .dialogo-box{display:flex;align-items:flex-start;gap:14px;background:rgba(255,255,255,.04);border:1px solid rgba(168,197,160,.2);border-radius:8px;padding:18px 20px;animation:slideDown .4s ease}
    .dialogo-avatar{font-size:28px;flex-shrink:0;background:rgba(45,90,61,.4);width:50px;height:50px;border-radius:50%;display:flex;align-items:center;justify-content:center;border:1px solid rgba(107,158,120,.4)}
    .dialogo-corpo{display:flex;flex-direction:column;gap:4px}
    .dialogo-nome{font-size:11px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--verde-folha)}
    .dialogo-texto{font-family:'Crimson Pro',serif;font-size:16px;font-style:italic;line-height:1.65;color:rgba(245,240,232,.88)}

    /* Cards */
    .card-conteudo{background:rgba(255,255,255,.05);border:1px solid rgba(168,197,160,.18);border-radius:8px;overflow:hidden}
    .card-header{display:flex;align-items:center;gap:10px;padding:12px 16px;background:rgba(74,124,89,.15);border-bottom:1px solid rgba(168,197,120,.1);cursor:pointer;user-select:none}
    .card-header-titulo{font-size:13px;font-weight:700;letter-spacing:.06em;color:var(--verde-claro)}
    .card-seta{margin-left:auto;color:var(--verde-musgo);transition:transform .25s;font-size:13px}
    .card-seta.aberto{transform:rotate(180deg)}
    .card-body{padding:16px 18px;display:flex;flex-direction:column;gap:10px;animation:slideDown .25s ease}
    .card-texto{font-family:'Crimson Pro',serif;font-size:16px;line-height:1.7;color:rgba(245,240,232,.88)}
    .nc{font-style:italic}
    .card-mnem{background:rgba(212,168,83,.08);border:1px solid rgba(212,168,83,.25);border-radius:6px;padding:12px 14px;font-size:13px;font-weight:700;color:var(--ocre);letter-spacing:.04em}
    .card-tabela{width:100%;border-collapse:collapse}
    .card-tabela th{text-align:left;padding:8px 12px;font-size:11px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--verde-folha);border-bottom:1px solid rgba(168,197,160,.2)}
    .card-tabela td{padding:9px 12px;font-family:'Crimson Pro',serif;font-size:15px;color:rgba(245,240,232,.85);border-bottom:1px solid rgba(255,255,255,.05);vertical-align:top}
    .card-tabela td:first-child{font-weight:700;color:var(--verde-claro);white-space:nowrap}

    /* Quiz */
    .quiz-num{font-size:11px;font-weight:700;letter-spacing:.15em;text-transform:uppercase;color:rgba(168,197,160,.6);margin-bottom:8px}
    .quiz-enunciado{font-family:'Crimson Pro',serif;font-size:clamp(15px,2.4vw,18px);line-height:1.7;color:var(--creme);margin-bottom:16px;padding:16px 18px;background:rgba(255,255,255,.04);border-left:3px solid var(--verde-musgo);border-radius:0 6px 6px 0}
    .quiz-opcoes{display:flex;flex-direction:column;gap:9px;margin-bottom:14px}
    .quiz-opcao{display:flex;align-items:flex-start;gap:12px;padding:13px 16px;background:rgba(255,255,255,.04);border:1.5px solid rgba(168,197,160,.2);border-radius:6px;cursor:pointer;transition:border-color .2s,background .2s;font-family:'Crimson Pro',serif;font-size:16px;line-height:1.5;color:rgba(245,240,232,.88);text-align:left;width:100%}
    .quiz-opcao:hover:not(:disabled){border-color:var(--verde-folha);background:rgba(107,158,120,.1)}
    .quiz-opcao:disabled{cursor:default}
    .quiz-opcao.correta{border-color:var(--acerto)!important;background:var(--acerto-bg)!important}
    .quiz-opcao.errada{border-color:var(--erro)!important;background:var(--erro-bg)!important}
    .quiz-opcao.neutra-off{opacity:.45}
    .quiz-letra{font-size:12px;font-weight:700;color:rgba(168,197,160,.7);flex-shrink:0;margin-top:2px;min-width:18px}

    /* Feedback */
    .feedback-box{border-radius:8px;padding:16px 18px;animation:slideDown .3s ease;display:flex;gap:12px;align-items:flex-start}
    .feedback-box.acerto{background:var(--acerto-bg);border:1px solid rgba(45,122,71,.5)}
    .feedback-box.erro  {background:var(--erro-bg);  border:1px solid rgba(139,45,45,.5)}
    .feedback-icone{font-size:20px;flex-shrink:0}
    .feedback-texto{font-family:'Crimson Pro',serif;font-size:15px;line-height:1.65;color:rgba(245,240,232,.9)}

    /* Dica */
    .dica-row{display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-top:4px}
    .btn-dica{display:flex;align-items:center;gap:6px;padding:8px 14px;background:transparent;border:1.5px solid rgba(212,168,83,.35);color:var(--ocre);border-radius:20px;font-size:12px;font-weight:700;letter-spacing:.08em;cursor:pointer;transition:border-color .2s,background .2s}
    .btn-dica:hover:not(:disabled){border-color:var(--ocre);background:rgba(212,168,83,.08)}
    .btn-dica:disabled{opacity:.4;cursor:default}
    .dica-custo{font-size:11px;color:rgba(212,168,83,.6);font-style:italic}
    .dica-caixa{background:rgba(212,168,83,.08);border:1px solid rgba(212,168,83,.3);border-radius:6px;padding:12px 14px;margin-top:8px;font-family:'Crimson Pro',serif;font-size:15px;font-style:italic;color:rgba(245,240,232,.85);line-height:1.6;animation:slideDown .3s ease}
    .dica-caixa::before{content:'💡 ';font-style:normal}

    /* Overlay aviso */
    .overlay{position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:200;display:flex;align-items:center;justify-content:center;padding:24px;animation:fadeIn .2s ease}
    .aviso-box{background:#152d1e;border:1px solid rgba(212,168,83,.4);border-radius:12px;padding:28px 32px;max-width:420px;width:100%;display:flex;flex-direction:column;gap:16px;animation:popIn .25s ease}
    .aviso-titulo{font-family:'Playfair Display',serif;font-size:22px;font-weight:700;color:var(--creme)}
    .aviso-texto{font-family:'Crimson Pro',serif;font-size:16px;line-height:1.6;color:rgba(245,240,232,.8)}
    .aviso-btns{display:flex;gap:10px}
    .btn-sim{flex:1;padding:12px;background:linear-gradient(135deg,var(--terra),var(--ocre));color:var(--escuro);border:none;border-radius:4px;font-size:14px;font-weight:700;cursor:pointer}
    .btn-nao{flex:1;padding:12px;background:transparent;border:1.5px solid rgba(168,197,160,.3);color:rgba(168,197,160,.7);border-radius:4px;font-size:14px;font-weight:700;cursor:pointer}

    /* Arrasta-solta */
    .drag-titulo{font-family:'Playfair Display',serif;font-size:20px;font-weight:700;color:var(--creme);margin-bottom:4px}
    .drag-instrucao{font-family:'Crimson Pro',serif;font-size:15px;font-style:italic;color:rgba(168,197,160,.8);margin-bottom:14px}
    .drag-banco{display:flex;flex-wrap:wrap;gap:8px;padding:14px;background:rgba(255,255,255,.03);border:1px solid rgba(168,197,160,.12);border-radius:8px;margin-bottom:12px;min-height:56px}
    .drag-item{padding:9px 16px;background:rgba(45,90,61,.4);border:1.5px solid rgba(107,158,120,.4);border-radius:20px;font-size:13px;font-weight:700;color:var(--creme);cursor:grab;user-select:none;transition:transform .15s,box-shadow .15s;animation:popIn .2s ease}
    .drag-item:hover{transform:translateY(-2px);box-shadow:0 4px 14px rgba(0,0,0,.3)}
    .drag-item.selecionado{background:rgba(212,168,83,.25);border-color:var(--ocre)}
    .drag-slots{display:flex;flex-direction:column;gap:6px;margin-bottom:12px}
    .drag-slot-row{display:flex;align-items:center;gap:6px}
    .drag-slot-num{width:22px;font-size:11px;font-weight:700;color:rgba(168,197,160,.5);text-align:right;flex-shrink:0}
    .drag-zone{flex:1;min-height:44px;border:2px dashed rgba(168,197,160,.25);border-radius:6px;display:flex;align-items:center;padding:0 12px;background:rgba(255,255,255,.03);transition:border-color .2s,background .2s;cursor:pointer}
    .drag-zone:hover{border-color:rgba(168,197,160,.5);background:rgba(107,158,120,.07)}
    .drag-zone.ok{border-color:var(--acerto);background:var(--acerto-bg)}
    .drag-zone.fail{border-color:var(--erro);background:var(--erro-bg)}
    .drag-zone-hint{font-size:12px;color:rgba(168,197,160,.35);font-style:italic;pointer-events:none}
    .drag-zone-chip{padding:7px 14px;background:rgba(45,90,61,.5);border:1.5px solid rgba(107,158,120,.5);border-radius:20px;font-size:13px;font-weight:700;color:var(--creme);cursor:grab}
    .drag-zone-chip.ok{background:rgba(45,122,71,.35);border-color:var(--acerto);color:var(--verde-claro)}
    .drag-zone-chip.fail{background:rgba(139,45,45,.35);border-color:var(--erro)}
    .drag-acoes{display:flex;gap:10px;flex-wrap:wrap}
    .btn-verificar{flex:1;min-width:100px;padding:13px 20px;background:linear-gradient(135deg,var(--verde-medio),var(--verde-musgo));color:var(--creme);border:none;border-radius:4px;font-size:14px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;cursor:pointer;transition:transform .2s,opacity .2s}
    .btn-verificar:hover:not(:disabled){transform:translateY(-2px)}
    .btn-verificar:disabled{opacity:.4;cursor:not-allowed}
    .btn-limpar{padding:13px 20px;background:transparent;border:1.5px solid rgba(168,197,160,.3);color:rgba(168,197,160,.7);border-radius:4px;font-size:13px;font-weight:700;cursor:pointer;transition:border-color .2s,color .2s}
    .btn-limpar:hover{border-color:var(--verde-folha);color:var(--verde-folha)}

    /* Nav */
    .btn-avancar{width:100%;padding:15px;background:linear-gradient(135deg,var(--verde-medio),var(--verde-musgo));color:var(--creme);border:none;border-radius:4px;font-size:14px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;cursor:pointer;transition:transform .2s,box-shadow .2s;display:flex;align-items:center;justify-content:center;gap:10px}
    .btn-avancar:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(45,90,61,.5)}

    /* Transição de fase */
    .fase-transicao{width:100%;min-height:80vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px 24px;gap:24px;text-align:center}
    .transicao-badge{font-size:64px;animation:popIn .5s ease}
    .transicao-titulo{font-family:'Playfair Display',serif;font-size:clamp(22px,4vw,34px);font-weight:700;color:var(--creme)}
    .transicao-sub{font-family:'Crimson Pro',serif;font-size:17px;font-style:italic;color:var(--verde-claro)}
    .transicao-fala{max-width:560px;padding:18px 22px;background:rgba(255,255,255,.04);border:1px solid rgba(168,197,160,.2);border-radius:8px;font-family:'Crimson Pro',serif;font-size:16px;font-style:italic;line-height:1.7;color:rgba(245,240,232,.85)}
    .btn-proxima{padding:16px 48px;background:linear-gradient(135deg,var(--verde-medio),var(--verde-musgo));color:var(--creme);border:none;border-radius:4px;font-size:15px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;cursor:pointer;transition:transform .2s,box-shadow .2s}
    .btn-proxima:hover{transform:translateY(-3px);box-shadow:0 10px 30px rgba(45,90,61,.5)}

    .placeholder-fase{width:100%;min-height:70vh;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:20px;padding:40px;text-align:center}

    /* ── MODO AEE ── */
    /* Todo o texto em caixa alta, exceto nomes científicos */
    .aee-modo { font-family:'Lato',sans-serif !important; }
    .aee-modo p, .aee-modo span, .aee-modo h1, .aee-modo h2, .aee-modo h3,
    .aee-modo label, .aee-modo button, .aee-modo li, .aee-modo td, .aee-modo th,
    .aee-modo div { text-transform:uppercase; letter-spacing:.04em; }
    /* Exceção: nomes científicos mantêm grafia correta */
    .aee-modo .nc    { text-transform:none !important; font-style:italic;
                       font-family:'Crimson Pro',serif; letter-spacing:.01em; }
    /* Tamanho de fonte AEE ligeiramente maior para legibilidade */
    .aee-modo .quiz-enunciado { font-size:clamp(15px,2.6vw,19px); line-height:1.8; font-family:'Lato',sans-serif !important; }
    .aee-modo .quiz-opcao     { font-size:15px; line-height:1.6; font-family:'Lato',sans-serif !important; }
    .aee-modo .feedback-texto { font-size:14px; line-height:1.7; font-family:'Lato',sans-serif !important; }
    .aee-modo .card-texto     { font-size:15px; line-height:1.75; font-family:'Lato',sans-serif !important; }
    .aee-modo .dialogo-texto  { font-size:15px; line-height:1.7; font-family:'Lato',sans-serif !important; font-style:normal !important; }
    .aee-modo .dica-caixa     { font-family:'Lato',sans-serif !important; font-style:normal !important; }
    .aee-modo .transicao-fala { font-family:'Lato',sans-serif !important; font-style:normal !important; }
    .aee-modo .drag-titulo     { font-family:'Lato',sans-serif !important; }
    .aee-modo .drag-instrucao  { font-family:'Lato',sans-serif !important; font-style:normal !important; }
    .aee-modo .aprend-texto    { font-family:'Lato',sans-serif !important; }
    .aee-modo .quiz-num        { font-family:'Lato',sans-serif !important; letter-spacing:.1em; }
    .aee-modo .card-mnem       { font-family:'Lato',sans-serif !important; font-style:normal !important; }
    /* Certificado AEE — manter visual premium mas sans-serif */
    .aee-modo .cert-quote      { font-family:'Lato',sans-serif !important; font-style:normal !important; }
    /* Badge AEE no HUD */
    .hud-aee-badge { background:rgba(212,168,83,.2); border:1px solid rgba(212,168,83,.5);
      color:var(--ocre); font-size:10px; font-weight:700; letter-spacing:.1em;
      padding:3px 8px; border-radius:10px; white-space:nowrap; }

    /* Tela seleção versão */
    .tela-versao { width:100%; min-height:100vh; position:relative; display:flex;
      flex-direction:column; align-items:center; justify-content:center;
      padding:40px 24px; overflow:hidden; }
    .bg-versao { position:absolute; inset:0; background:
      radial-gradient(ellipse at 30% 70%,rgba(74,124,89,.4) 0%,transparent 50%),
      linear-gradient(160deg,#0f1f16,#1a3a2a,#0a1a10); z-index:0; }
    .versao-content { position:relative; z-index:2; width:100%; max-width:680px;
      display:flex; flex-direction:column; align-items:center; gap:32px; text-align:center; }
    .versao-cards { display:grid; grid-template-columns:1fr 1fr; gap:16px; width:100%; }
    .versao-card { background:rgba(255,255,255,.05); border:2px solid rgba(168,197,160,.2);
      border-radius:12px; padding:28px 24px; cursor:pointer; display:flex;
      flex-direction:column; align-items:center; gap:14px; transition:border-color .2s,
      background .2s, transform .2s; }
    .versao-card:hover { border-color:var(--verde-folha); background:rgba(107,158,120,.1);
      transform:translateY(-4px); }
    .versao-card.aee { border-color:rgba(212,168,83,.3); }
    .versao-card.aee:hover { border-color:var(--ocre); background:rgba(212,168,83,.08); }
    .versao-icone { font-size:40px; }
    .versao-titulo { font-family:'Playfair Display',serif; font-size:20px; font-weight:700;
      color:var(--creme); }
    .versao-desc { font-family:'Crimson Pro',serif; font-size:14px; line-height:1.6;
      color:rgba(245,240,232,.7); font-style:italic; }
    .versao-tags { display:flex; flex-wrap:wrap; gap:6px; justify-content:center; }
    .versao-tag { font-size:10px; font-weight:700; letter-spacing:.08em; text-transform:uppercase;
      padding:3px 10px; border-radius:12px; }
    .versao-tag.verde { background:rgba(107,158,120,.2); color:var(--verde-claro); border:1px solid rgba(107,158,120,.35); }
    .versao-tag.ocre  { background:rgba(212,168,83,.15); color:var(--ocre); border:1px solid rgba(212,168,83,.3); }

    @media(max-width:600px){
      .aprend-card{padding:24px 18px}
      .hud{padding:10px 14px;gap:8px}
      .fase-content{padding:14px}
      .dra-panel{flex-direction:column}
      .sinopse{padding:18px 20px 18px 36px}
      .versao-cards{grid-template-columns:1fr;}
    }
  `}</style>
);

