// ─── COMPONENTES REUTILIZÁVEIS ─────────────────────────────────────────────────
function CardExpansivel({card}){
  const [aberto,setAberto]=useState(true);
  return(
    <div className="card-conteudo">
      <div className="card-header" onClick={()=>setAberto(a=>!a)}>
        <span style={{fontSize:16}}>{card.icone}</span>
        <span className="card-header-titulo">{card.titulo}</span>
        <span className={`card-seta${aberto?" aberto":""}`}>▼</span>
      </div>
      {aberto&&<div className="card-body">{card.corpo}</div>}
    </div>
  );
}

function AvisoDica({desconto,textoExtra,onSim,onNao}){
  return(
    <div className="overlay">
      <div className="aviso-box">
        <p className="aviso-titulo">💡 Usar dica?</p>
        <p className="aviso-texto">
          Usar a dica reduzirá sua pontuação nesta questão em{" "}
          <strong style={{color:"var(--ocre)"}}>{desconto}%</strong>
          {textoExtra&&<span style={{color:"rgba(212,168,83,.7)",fontSize:13}}> {textoExtra}</span>}.
        </p>
        <div className="aviso-btns">
          <button className="btn-sim" onClick={onSim}>Sim, usar dica</button>
          <button className="btn-nao" onClick={onNao}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

const CAIXAS_HIERARQUIA_B64=`data:image/jpeg;base64,`;

function QuizItem({q,onResponder,versao}){
  const [sel,setSel]=useState(null);
  const [feito,setFeito]=useState(false);
  const [dicaNivel,setDicaNivel]=useState(0); // 0=nenhuma,1=primeira,2=segunda
  const [aviso,setAviso]=useState(false);
  const [proxNivel,setProxNivel]=useState(1);

  const integradora=!!q.integradora;
  const isAee=versao==="aee";
  // AEE: dica gratuita (andaime pedagógico — não penaliza)
  // Regular: -50% normais; integradoras -30% por dica (máx -60%)
  const custoPorDica=integradora?30:50;

  const multiplicador=()=>{
    if(isAee)return 1;
    if(dicaNivel===0)return 1;
    if(integradora)return dicaNivel===1?0.7:0.4;
    return 0.5;
  };

  // AEE: exibe dica diretamente sem modal; Regular: abre confirmação
  const usarDica=(nivel)=>{
    if(isAee){setDicaNivel(nivel);}
    else{setProxNivel(nivel);setAviso(true);}
  };

  const responder=(letra)=>{
    if(feito)return;
    setSel(letra);setFeito(true);
    const ok=q.opcoes.find(o=>o.l===letra).ok;
    onResponder(ok,ok?Math.round(q.pts*multiplicador()):0);
  };
  const classeOpcao=(letra)=>{
    if(!feito)return"";
    const op=q.opcoes.find(o=>o.l===letra);
    if(op.ok)return"correta";
    if(letra===sel)return"errada";
    return"neutra-off";
  };
  const acertou=feito&&q.opcoes.find(o=>o.l===sel)?.ok;

  const textoOpcao=(op)=>q.tipo==="nomenclatura"
    ?<em className="nc" style={{fontSize:17}}>{op.t}</em>
    :<span>{op.t}</span>;

  const podeDica=integradora?(dicaNivel<2):(dicaNivel<1);
  const desconto=integradora?`-${custoPorDica}% por dica (máx. -60%)`:`-${custoPorDica}%`;


  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      {aviso&&!isAee&&<AvisoDica
        desconto={custoPorDica}
        textoExtra={integradora?`(${desconto})`:""}
        onSim={()=>{setAviso(false);setDicaNivel(proxNivel);}}
        onNao={()=>setAviso(false)}/>}

      {integradora&&(
        <div style={{display:"flex",alignItems:"center",gap:8,padding:"8px 14px",
          background:"rgba(212,168,83,.08)",border:"1px solid rgba(212,168,83,.25)",
          borderRadius:6,marginBottom:4}}>
          <span style={{fontSize:16}}>⭐</span>
          <span style={{fontSize:12,fontWeight:700,color:"var(--ocre)",letterSpacing:".08em"}}>
            {isAee
              ?`QUESTÃO ESPECIAL — ${q.pts} PONTOS — 2 DICAS DISPONÍVEIS (GRATUITAS)`
              :`QUESTÃO INTEGRADORA — ${q.pts} pontos — 2 dicas disponíveis (-30% cada)`}
          </span>
        </div>
      )}

      <p className="quiz-num">{q.num}</p>
      <p className="quiz-enunciado">{q.enunciado}</p>
      <div className="quiz-opcoes">
        {q.opcoes.map(op=>(
          <button key={op.l} className={`quiz-opcao ${classeOpcao(op.l)}`}
            onClick={()=>responder(op.l)} disabled={feito}>
            <span className="quiz-letra">{op.l}</span>
            {textoOpcao(op)}
          </button>
        ))}
      </div>

      {!feito&&(
        <div className="dica-row">
          {integradora?(
            <>
              <button className="btn-dica" onClick={()=>usarDica(1)} disabled={dicaNivel>=1}>
                💡 {isAee?"DICA 1":"Dica 1"}{" "}
                {dicaNivel<1&&!isAee&&<span className="dica-custo">(-30%)</span>}
                {dicaNivel>=1&&(isAee?" (USADA)":" (usada)")}
              </button>
              <button className="btn-dica" onClick={()=>usarDica(2)} disabled={dicaNivel>=2||dicaNivel<1}>
                💡 {isAee?"DICA 2":"Dica 2"}{" "}
                {dicaNivel===1&&!isAee&&<span className="dica-custo">(-30%)</span>}
                {dicaNivel>=2&&(isAee?" (USADA)":" (usada)")}
                {dicaNivel<1&&<span className="dica-custo" style={{opacity:.5}}>{isAee?"(USE DICA 1 PRIMEIRO)":"(use dica 1 primeiro)"}</span>}
              </button>
            </>
          ):(
            <button className="btn-dica" onClick={()=>usarDica(1)} disabled={dicaNivel>=1}>
              💡 {isAee?(dicaNivel>=1?"DICA USADA":"VER DICA"):(dicaNivel>=1?"Dica usada":"Usar dica")}
              {dicaNivel<1&&!isAee&&<span className="dica-custo">(-50%)</span>}
            </button>
          )}
        </div>
      )}

      {dicaNivel>=1&&!feito&&(
        <div className="dica-caixa">{integradora?q.dica1:q.dica}</div>
      )}
      {dicaNivel>=2&&!feito&&(
        <div className="dica-caixa" style={{marginTop:6,borderColor:"rgba(212,168,83,.5)"}}>{q.dica2}</div>
      )}

      {feito&&(
        <div
          className={`feedback-box ${acertou?"acerto":"erro"}`}
          style={isAee&&acertou?{
            animation:"aeeAcertoGlow .7s ease forwards",
            border:"2px solid rgba(45,200,100,.7)",
            position:"relative",
          }:{}}>
          <span
            className="feedback-icone"
            style={isAee&&acertou?{animation:"aeeAcertoEstrela .5s ease forwards, aeeIconePulso 1s ease .5s 2"}:{}}>
            {acertou?"✅":"❌"}
          </span>
          <p className="feedback-texto">{q.fb[sel]}</p>
          {isAee&&acertou&&(
            <div aria-hidden="true" style={{
              position:"absolute",top:-14,right:12,
              fontSize:22,animation:"aeeAcertoEstrela .6s ease .1s both",
              pointerEvents:"none",userSelect:"none"}}>⭐</div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── ARRASTA E SOLTA ──────────────────────────────────────────────────────────
function ArrastaSolta({onConcluido}){
  const [banco,setBanco]=useState([...NIVEIS_BANCO]);
  const [slots,setSlots]=useState(Array(8).fill(null));
  const [status,setStatus]=useState("idle");
  const [tentativas,setTentativas]=useState(0);
  const [dicaUsada,setDicaUsada]=useState(false);
  const [dicaVis,setDicaVis]=useState(false);
  const [aviso,setAviso]=useState(false);
  const [sel,setSel]=useState(null);
  const [pronto,setPronto]=useState(false);
  const dragging=useRef(null);
  const dragFrom=useRef(null);
  const done=useRef(false);

  const colocarNoSlot=(idx)=>{
    if(status!=="idle"||!sel)return;
    const ns=[...slots],nb=banco.filter(i=>i!==sel);
    if(ns[idx])nb.push(ns[idx]);
    ns[idx]=sel;
    setBanco(nb);setSlots(ns);setSel(null);
  };
  const removerSlot=(idx)=>{
    if(status!=="idle")return;
    if(sel){colocarNoSlot(idx);return;}
    const item=slots[idx];if(!item)return;
    const ns=[...slots];ns[idx]=null;
    setBanco(b=>[...b,item]);setSlots(ns);
  };
  const toggleBanco=(item)=>{ if(status!=="idle")return; setSel(s=>s===item?null:item); };
  const onDragStartBanco=(item)=>{dragging.current=item;dragFrom.current="banco";};
  const onDragStartSlot=(idx)=>{dragging.current=slots[idx];dragFrom.current=idx;};
  const onDropSlot=(idx)=>{
    if(!dragging.current)return;
    const item=dragging.current,from=dragFrom.current;
    const ns=[...slots],nb=[...banco];
    if(from==="banco"){const bi=nb.indexOf(item);if(bi>-1)nb.splice(bi,1);}
    else{const prev=ns[idx];ns[from]=null;if(prev&&from!==idx)nb.push(prev);}
    if(ns[idx]&&from==="banco")nb.push(ns[idx]);
    ns[idx]=item;
    setBanco(nb);setSlots(ns);setStatus("idle");
    dragging.current=null;dragFrom.current=null;
  };
  const onDropBanco=()=>{
    if(!dragging.current||dragFrom.current==="banco"){dragging.current=null;return;}
    const idx=dragFrom.current,ns=[...slots],item=ns[idx];
    ns[idx]=null;setBanco(b=>[...b,item]);setSlots(ns);setStatus("idle");
    dragging.current=null;dragFrom.current=null;
  };
  const verificar=()=>{
    if(slots.some(s=>!s))return;
    const ok=slots.every((s,i)=>s===NIVEIS_CORRETOS[i]);
    const t=tentativas+1;
    setTentativas(t);
    setStatus(ok?"correto":"errado");
    if(ok&&!done.current){
      done.current=true;
      onConcluido(Math.round(100*(dicaUsada?.5:1)));
      setPronto(true);
    } else if(!ok&&t>=2){
      // Mantém resposta do aluno — chipClass já mostra verde/vermelho por slot
      // Libera avanço com 0 pontos
      if(!done.current){done.current=true;onConcluido(0);}
      setPronto(true);
    }
  };
  const limpar=()=>{
    setBanco([...NIVEIS_BANCO]);setSlots(Array(8).fill(null));
    setStatus("idle");setSel(null);
  };
  const chipClass=(idx)=>{
    if(status==="correto")return"ok";
    if(status==="errado")return slots[idx]===NIVEIS_CORRETOS[idx]?"ok":"fail";
    return"";
  };
  const encerrado=status==="correto"||(status==="errado"&&tentativas>=2);

  return(
    <div>
      {aviso&&!isAee&&<AvisoDica desconto={50} onSim={()=>{setAviso(false);setDicaUsada(true);setDicaVis(true);}} onNao={()=>setAviso(false)}/>}
      <p className="drag-titulo">🌾 Organize a hierarquia da vida</p>
      <p className="drag-instrucao">Arraste (ou clique) os níveis do <strong style={{color:"var(--verde-claro)"}}>mais abrangente (1)</strong> ao <strong style={{color:"var(--ocre)"}}>mais específico (8)</strong>:</p>
      <div className="drag-banco" onDragOver={e=>e.preventDefault()} onDrop={onDropBanco}>
        {banco.length===0&&<span style={{fontSize:13,color:"rgba(168,197,160,.4)",fontStyle:"italic"}}>Todos os níveis posicionados ✓</span>}
        {banco.map(item=>(
          <div key={item} className={`drag-item${sel===item?" selecionado":""}`}
            draggable onDragStart={()=>onDragStartBanco(item)} onClick={()=>toggleBanco(item)}>{item}</div>
        ))}
      </div>
      <div className="drag-slots">
        {slots.map((slot,idx)=>(
          <div key={idx} className="drag-slot-row">
            <span className="drag-slot-num">{idx+1}</span>
            <div className={`drag-zone ${chipClass(idx)}`}
              onDragOver={e=>e.preventDefault()} onDrop={()=>onDropSlot(idx)}
              onClick={()=>{if(sel)colocarNoSlot(idx);else removerSlot(idx);}}>
              {slot
                ?<div className={`drag-zone-chip ${chipClass(idx)}`}
                    draggable onDragStart={()=>onDragStartSlot(idx)}
                    onClick={e=>{e.stopPropagation();if(!sel&&!encerrado)removerSlot(idx);}}>{slot}</div>
                :<span className="drag-zone-hint">{sel?`↙ Colocar "${sel}" aqui`:"Solte aqui..."}</span>}
            </div>
          </div>
        ))}
      </div>

      {/* Dica — só enquanto não encerrado e antes da 1ª tentativa */}
      {status==="idle"&&tentativas===0&&(
        <div className="dica-row" style={{marginBottom:10}}>
          <button className="btn-dica" onClick={()=>setAviso(true)} disabled={dicaUsada}>
            💡 {dicaUsada?"Dica usada":"Usar dica"}
            {!dicaUsada&&<span className="dica-custo">(-50% dos pontos)</span>}
          </button>
        </div>
      )}
      {dicaVis&&!encerrado&&<div className="dica-caixa" style={{marginBottom:10}}>Pense em caixas dentro de caixas: qual é a "caixa maior"? Esse é o nível que vai no topo.</div>}

      {/* Feedback */}
      {status==="correto"&&(
        <div className="feedback-box acerto" style={{marginBottom:10}}>
          <span className="feedback-icone">✅</span>
          <p className="feedback-texto"><strong>Perfeito!</strong> Hierarquia completa: Domínio → Reino → Filo → Classe → Ordem → Família → Gênero → Espécie. Cada nível "abraça" todos os que estão abaixo.</p>
        </div>
      )}
      {status==="errado"&&tentativas<2&&(
        <div className="feedback-box erro" style={{marginBottom:10}}>
          <span className="feedback-icone">❌</span>
          <p className="feedback-texto">Quase! Use o mnemônico <strong>DoReFiCOFaGE</strong>. Você tem mais {2-tentativas} tentativa(s).</p>
        </div>
      )}
      {status==="errado"&&tentativas>=2&&(
        <div className="feedback-box erro" style={{marginBottom:10}}>
          <span className="feedback-icone">📖</span>
          <div className="feedback-texto">
            <p style={{marginBottom:8}}>Os itens marcados em <strong style={{color:"var(--acerto)"}}>verde</strong> estavam corretos; em <strong style={{color:"var(--erro,#e08080)"}}>vermelho</strong>, incorretos.</p>
            <p style={{marginBottom:6}}>A sequência correta é:</p>
            <p style={{fontFamily:"'Crimson Pro',serif",fontSize:15,lineHeight:1.8}}>
              {NIVEIS_CORRETOS.map((n,i)=>(
                <span key={n}>
                  <strong style={{color: slots[i]===n ? "var(--acerto)" : "var(--erro,#e08080)"}}>{i+1}. {n}</strong>
                  {i<7&&<span style={{color:"rgba(168,197,160,.4)"}}> → </span>}
                </span>
              ))}
            </p>
            <p style={{marginTop:8,fontSize:13,color:"rgba(168,197,160,.6)"}}>Mnemônico: <em>Do</em>mínio · <em>Re</em>ino · <em>Fi</em>lo · <em>C</em>lasse · <em>O</em>rdem · <em>Fa</em>mília · <em>G</em>ênero · <em>E</em>spécie — <strong>DoReFiCOFaGE</strong></p>
          </div>
        </div>
      )}

      {/* Ações: verificar/limpar enquanto aberto; avançar quando encerrado */}
      <div className="drag-acoes">
        {!encerrado&&(
          <><button className="btn-verificar" onClick={verificar} disabled={slots.some(s=>!s)}>✓ VERIFICAR</button>
          <button className="btn-limpar" onClick={limpar}>↺ Limpar</button></>
        )}
      </div>
    </div>
  );
}

// ─── FASE GENÉRICA ────────────────────────────────────────────────────────────

// ─── CLASSIFICA FATORES ─────────────────────────────────────────────────────
function ClassificaFatores({onConcluido}){
  const [categorias,setCategorias]=useState({favoravel:[],limitante:[]});
  const [banco,setBanco]=useState([...FATORES_PANTANAL]);
  const [status,setStatus]=useState("idle"); // idle | correto | errado
  const [tentativas,setTentativas]=useState(0);
  const [dicaUsada,setDicaUsada]=useState(false);
  const [dicaVis,setDicaVis]=useState(false);
  const [aviso,setAviso]=useState(false);
  const [sel,setSel]=useState(null); // item selecionado do banco
  const done=useRef(false);

  const moverParaCategoria=(cat)=>{
    if(!sel||status!=="idle")return;
    const item=sel;
    setBanco(b=>b.filter(i=>i.id!==item.id));
    setCategorias(c=>({...c,[cat]:[...c[cat],item]}));
    setSel(null);
  };
  const removerDaCategoria=(cat,item)=>{
    if(status!=="idle")return;
    setCategorias(c=>({...c,[cat]:c[cat].filter(i=>i.id!==item.id)}));
    setBanco(b=>[...b,item]);
  };
  const toggleSel=(item)=>{
    if(status!=="idle")return;
    setSel(s=>s?.id===item.id?null:item);
  };

  const tudo=[...categorias.favoravel,...categorias.limitante];
  const pronto=tudo.length===FATORES_PANTANAL.length;

  const verificar=()=>{
    if(!pronto)return;
    const erros=[];
    categorias.favoravel.forEach(i=>{if(i.correto!=="favoravel")erros.push(i.id);});
    categorias.limitante.forEach(i=>{if(i.correto!=="limitante")erros.push(i.id);});
    const ok=erros.length===0;
    const t=tentativas+1;setTentativas(t);
    setStatus(ok?"correto":"errado");
    if(ok&&!done.current){
      done.current=true;
      onConcluido(Math.round(150*(dicaUsada?.5:1)));
    } else if(!ok&&t>=2){
      // Exibir gabarito e liberar avanço com 0 pontos
      setCategorias({
        favoravel:FATORES_PANTANAL.filter(i=>i.correto==="favoravel"),
        limitante:FATORES_PANTANAL.filter(i=>i.correto==="limitante"),
      });
      setBanco([]);
      if(!done.current){done.current=true;onConcluido(0);}
    }
  };
  const limpar=()=>{
    setCategorias({favoravel:[],limitante:[]});
    setBanco([...FATORES_PANTANAL]);
    setStatus("idle");setSel(null);
  };

  const chipColor=(item,cat)=>{
    if(status==="idle")return{};
    if(item.correto===cat)return{borderColor:"var(--acerto)",background:"rgba(45,122,71,.25)",color:"var(--verde-claro)"};
    return{borderColor:"var(--erro)",background:"rgba(139,45,45,.25)",color:"#e08080"};
  };

  return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      {aviso&&!isAee&&<AvisoDica desconto={50}
        onSim={()=>{setAviso(false);setDicaUsada(true);setDicaVis(true);}}
        onNao={()=>setAviso(false)}/>}

      <p className="drag-titulo">🌊 Classifique os fatores do Pantanal</p>
      <p className="drag-instrucao">
        Selecione um fator do banco e clique na categoria correta: <strong style={{color:"var(--verde-claro)"}}>Favorável</strong> ou <strong style={{color:"var(--ocre)"}}>Limitante</strong> para a biodiversidade local.
        {sel&&<span style={{color:"var(--ocre)",marginLeft:8}}>Selecionado: "{sel.label}"</span>}
      </p>

      {/* Banco */}
      <div className="drag-banco" style={{minHeight:52}}>
        {banco.length===0&&<span style={{fontSize:13,color:"rgba(168,197,160,.4)",fontStyle:"italic"}}>Todos os fatores classificados ✓</span>}
        {banco.map(item=>(
          <div key={item.id}
            className={`drag-item${sel?.id===item.id?" selecionado":""}`}
            onClick={()=>toggleSel(item)}>
            {item.label}
          </div>
        ))}
      </div>

      {/* Categorias */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
        {[
          {cat:"favoravel",label:"✅ Favorável",cor:"var(--acerto)",fundo:"rgba(45,122,71,.08)",borda:"rgba(45,122,71,.3)"},
          {cat:"limitante",label:"⚠️ Limitante",cor:"var(--ocre)",fundo:"rgba(212,168,83,.08)",borda:"rgba(212,168,83,.3)"},
        ].map(({cat,label,cor,fundo,borda})=>(
          <div key={cat}
            onClick={()=>{ if(sel)moverParaCategoria(cat); }}
            style={{
              minHeight:120,border:`2px dashed ${borda}`,borderRadius:8,
              background:fundo,padding:12,cursor:sel?"pointer":"default",
              transition:"border-color .2s,background .2s",
              ...(sel?{borderColor:cor,background:`${fundo.replace('.08','.15')}`}:{}),
            }}>
            <p style={{fontSize:12,fontWeight:700,letterSpacing:".1em",textTransform:"uppercase",color:cor,marginBottom:10}}>{label}</p>
            <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
              {categorias[cat].map(item=>(
                <div key={item.id}
                  onClick={e=>{e.stopPropagation();removerDaCategoria(cat,item);}}
                  style={{
                    padding:"7px 12px",borderRadius:20,
                    border:`1.5px solid ${status==="idle"?"rgba(168,197,160,.4)":item.correto===cat?"var(--acerto)":"var(--erro)"}`,
                    background:status==="idle"?"rgba(45,90,61,.4)":item.correto===cat?"rgba(45,122,71,.3)":"rgba(139,45,45,.3)",
                    color:status==="idle"?"var(--creme)":item.correto===cat?"var(--verde-claro)":"#e08080",
                    fontSize:12,fontWeight:700,cursor:status==="idle"?"pointer":"default",
                    userSelect:"none",transition:"all .2s",
                  }}
                  title={status==="idle"?"Clique para devolver ao banco":""}>
                  {item.label}
                  {status==="idle"&&<span style={{marginLeft:4,opacity:.5,fontSize:10}}>×</span>}
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Dica */}
      {status==="idle"&&tentativas===0&&(
        <div className="dica-row">
          <button className="btn-dica" onClick={()=>setAviso(true)} disabled={dicaUsada}>
            💡 {dicaUsada?"Dica usada":"Usar dica"}
            {!dicaUsada&&<span className="dica-custo">(-50% dos pontos)</span>}
          </button>
        </div>
      )}
      {dicaVis&&<div className="dica-caixa">Um fator é limitante quando está abaixo do mínimo necessário OU quando ultrapassa o máximo tolerado. Pense: quais desses fatores prejudicam espécies que precisam de solo seco ou de luz solar direta?</div>}

      {/* Feedback */}
      {status==="correto"&&(
        <div className="feedback-box acerto">
          <span className="feedback-icone">✅</span>
          <p className="feedback-texto"><strong>Excelente!</strong> Você identificou corretamente os fatores favoráveis e limitantes. No Pantanal, a inundação prolongada limita espécies adaptadas ao solo seco (xéricas), e a ausência de luz no fundo limita fotossintetizantes.</p>
        </div>
      )}
      {status==="errado"&&tentativas<2&&(
        <div className="feedback-box erro">
          <span className="feedback-icone">❌</span>
          <p className="feedback-texto">Alguns fatores estão na categoria errada. Lembre: limitante = aquilo que restringe a vida de certas espécies. Você tem mais {2-tentativas} tentativa(s).</p>
        </div>
      )}
      {status==="errado"&&tentativas>=2&&(
        <div className="feedback-box erro">
          <span className="feedback-icone">📖</span>
          <p className="feedback-texto">A classificação correta foi exibida. Revise os cards sobre fator limitante e Lei do Mínimo de Liebig.</p>
        </div>
      )}

      {/* Ações */}
      <div className="drag-acoes">
        {status==="idle"&&tentativas<2&&(
          <><button className="btn-verificar" onClick={verificar} disabled={!pronto}>✓ VERIFICAR</button>
          <button className="btn-limpar" onClick={limpar}>↺ Limpar</button></>
        )}
        {status==="errado"&&tentativas<2&&(
          <><button className="btn-verificar" onClick={verificar} disabled={!pronto}>✓ TENTAR NOVAMENTE</button>
          <button className="btn-limpar" onClick={limpar}>↺ Limpar</button></>
        )}
      </div>
    </div>
  );
}

// ─── ORDEM POR CLIQUE (AEE) ──────────────────────────────────────────────────
function OrdemClique({onConcluido}){
  const [disponiveis,setDisponiveis]=useState([...NIVEIS_BANCO]);
  const [sequencia,setSequencia]=useState([]);
  const [status,setStatus]=useState("idle"); // idle | correto | errado
  const [tentativas,setTentativas]=useState(0);
  const done=useRef(false);

  const clicarItem=(item)=>{
    if(status!=="idle")return;
    setSequencia(s=>[...s,item]);
    setDisponiveis(d=>d.filter(i=>i!==item));
  };

  const desfazer=()=>{
    if(status!=="idle"||sequencia.length===0)return;
    const ultimo=sequencia[sequencia.length-1];
    setSequencia(s=>s.slice(0,-1));
    setDisponiveis(d=>[...d,ultimo]);
  };

  const verificar=()=>{
    if(sequencia.length<8)return;
    const ok=sequencia.every((s,i)=>s===NIVEIS_CORRETOS[i]);
    const t=tentativas+1;
    setTentativas(t);
    setStatus(ok?"correto":"errado");
    if(ok&&!done.current){
      done.current=true;
      onConcluido(100);
    } else if(!ok&&t>=2){
      if(!done.current){done.current=true;onConcluido(0);}
    }
  };

  const reiniciar=()=>{
    setDisponiveis([...NIVEIS_BANCO]);
    setSequencia([]);
    setStatus("idle");
  };

  const encerrado=status==="correto"||(status==="errado"&&tentativas>=2);

  const corSlot=(idx)=>{
    if(status==="idle") return{bg:"rgba(45,90,61,.5)",borda:"rgba(168,197,160,.4)",cor:"var(--creme)"};
    if(sequencia[idx]===NIVEIS_CORRETOS[idx]) return{bg:"rgba(45,122,71,.35)",borda:"var(--acerto)",cor:"var(--verde-claro)"};
    return{bg:"rgba(139,45,45,.3)",borda:"var(--erro,#c0392b)",cor:"#e08080"};
  };

  return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      <p className="drag-titulo" style={{fontSize:16}}>🌾 COLOQUE OS NÍVEIS NA ORDEM CERTA</p>
      <p className="drag-instrucao" style={{fontSize:14}}>
        CLIQUE NOS NÍVEIS NA ORDEM: DO <strong style={{color:"var(--verde-claro)"}}>MAIOR (1)</strong> PARA O <strong style={{color:"var(--ocre)"}}>MENOR (8)</strong>
      </p>

      {/* Botões disponíveis */}
      <div style={{display:"flex",flexWrap:"wrap",gap:8,minHeight:52,padding:10,
        background:"rgba(20,40,28,.4)",borderRadius:10,border:"1.5px dashed rgba(168,197,160,.25)"}}>
        {disponiveis.length===0
          ? <span style={{fontSize:13,color:"rgba(168,197,160,.4)",fontStyle:"italic",alignSelf:"center"}}>
              TODOS OS NÍVEIS FORAM ESCOLHIDOS ✓
            </span>
          : disponiveis.map(item=>(
            <button key={item} onClick={()=>clicarItem(item)}
              disabled={status!=="idle"}
              style={{padding:"10px 16px",borderRadius:24,border:"2px solid rgba(168,197,160,.5)",
                background:"rgba(45,90,61,.6)",color:"var(--creme)",
                fontSize:13,fontWeight:700,letterSpacing:".05em",cursor:"pointer",
                transition:"all .15s",fontFamily:"inherit"}}>
              {item}
            </button>
          ))
        }
      </div>

      {/* Sequência montada */}
      <div style={{display:"flex",flexDirection:"column",gap:6}}>
        {Array(8).fill(null).map((_,idx)=>{
          const filled=sequencia[idx];
          const {bg,borda,cor}=corSlot(idx);
          return(
            <div key={idx} style={{display:"flex",alignItems:"center",gap:10}}>
              <span style={{width:24,height:24,borderRadius:"50%",background:"rgba(168,197,160,.15)",
                border:"1.5px solid rgba(168,197,160,.3)",display:"flex",alignItems:"center",
                justifyContent:"center",fontSize:12,fontWeight:700,color:"rgba(168,197,160,.6)",
                flexShrink:0}}>{idx+1}</span>
              <div style={{flex:1,padding:"10px 14px",borderRadius:8,
                background:filled?bg:"rgba(20,40,28,.3)",
                border:`1.5px solid ${filled?borda:"rgba(168,197,160,.15)"}`,
                minHeight:40,display:"flex",alignItems:"center"}}>
                {filled
                  ? <span style={{fontWeight:700,fontSize:13,color:cor,letterSpacing:".04em"}}>{filled}</span>
                  : <span style={{fontSize:12,color:"rgba(168,197,160,.25)",fontStyle:"italic"}}>— CLIQUE EM UM NÍVEL ACIMA —</span>
                }
              </div>
              {status==="errado"&&tentativas>=2&&filled&&filled!==NIVEIS_CORRETOS[idx]&&(
                <span style={{fontSize:11,color:"rgba(168,197,160,.5)",whiteSpace:"nowrap"}}>
                  → {NIVEIS_CORRETOS[idx]}
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* Feedback */}
      {status==="correto"&&(
        <div className="feedback-box acerto">
          <span className="feedback-icone">✅</span>
          <p className="feedback-texto"><strong>MUITO BEM!</strong> SEQUÊNCIA CORRETA: DOMÍNIO → REINO → FILO → CLASSE → ORDEM → FAMÍLIA → GÊNERO → ESPÉCIE.</p>
        </div>
      )}
      {status==="errado"&&tentativas<2&&(
        <div className="feedback-box erro">
          <span className="feedback-icone">❌</span>
          <p className="feedback-texto">QUASE! TENTE NOVAMENTE. LEMBRE DO MNEMÔNICO: <strong>DoReFiCOFaGE</strong>.</p>
        </div>
      )}
      {status==="errado"&&tentativas>=2&&(
        <div className="feedback-box erro">
          <span className="feedback-icone">📖</span>
          <p className="feedback-texto">
            A ORDEM CORRETA ESTÁ INDICADA AO LADO DE CADA POSIÇÃO. <strong>DoReFiCOFaGE</strong>: DOMÍNIO · REINO · FILO · CLASSE · ORDEM · FAMÍLIA · GÊNERO · ESPÉCIE.
          </p>
        </div>
      )}

      {/* Ações */}
      <div className="drag-acoes">
        {!encerrado&&(
          <>
            {sequencia.length===8&&status==="idle"&&(
              <button className="btn-verificar" onClick={verificar}>✓ VERIFICAR</button>
            )}
            {status==="errado"&&tentativas<2&&(
              <button className="btn-verificar" onClick={reiniciar}>↺ TENTAR NOVAMENTE</button>
            )}
            {sequencia.length>0&&status==="idle"&&(
              <button className="btn-limpar" onClick={desfazer}>← DESFAZER ÚLTIMO</button>
            )}
          </>
        )}
      </div>
    </div>
  );
}

function FaseGenerica({config,onConcluir,onPontos,versao}){
  const [etapa,setEtapa]=useState("dialogo");
  const [qi,setQi]=useState(0);
  const [respondida,setRespondida]=useState(false);
  const [dragOk,setDragOk]=useState(false);
  const pontosRef=useRef(0);
  const addPts=(p)=>{pontosRef.current+=p;onPontos(p);};
  const avancarQuiz=()=>{
    setRespondida(false);
    if(qi<config.quiz.length-1)setQi(q=>q+1);
    else setEtapa("transicao");
  };

  if(etapa==="dialogo") return(
    <div style={{display:"flex",flexDirection:"column",gap:18}}>
      <div className="dialogo-box anim-1">
        <div className="dialogo-avatar">👩🏾‍🔬</div>
        <div className="dialogo-corpo">
          <span className="dialogo-nome">Dra. Conceição Ribeiro</span>
          <p className="dialogo-texto">{config.dialogoAbertura}</p>
        </div>
      </div>
      <button className="btn-avancar anim-2"
        onClick={()=>setEtapa(config.cards?.length?"cards":config.temDrag?"drag":config.temOrdemClique?"ordemclique":config.temDragCustom?"dragcustom":"quiz")}>
        📖 Ver conteúdo da fase →
      </button>
    </div>
  );
  if(etapa==="cards") return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      {config.cards.map(c=><CardExpansivel key={c.id} card={c}/>)}
      <button className="btn-avancar" onClick={()=>setEtapa(config.temDrag?"drag":config.temOrdemClique?"ordemclique":config.temDragCustom?"dragcustom":"quiz")}>
        {(config.temDrag||config.temOrdemClique||config.temDragCustom)?`${config.badge} Partir para o desafio →`:"📝 Iniciar questões →"}
      </button>
    </div>
  );
  if(etapa==="drag") return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      <ArrastaSolta onConcluido={(p)=>{addPts(p);setDragOk(true);}}/>
      {dragOk&&<button className="btn-avancar" onClick={()=>setEtapa("quiz")}>📝 Próximo desafio →</button>}
    </div>
  );
  if(etapa==="ordemclique") return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      {versao==="aee"&&(
        <div style={{background:"rgba(255,255,255,.04)",border:"1px solid rgba(168,197,160,.2)",borderRadius:10,padding:"12px 14px"}}>
          <p style={{fontWeight:700,fontSize:13,marginBottom:8,color:"var(--verde-claro)"}}>📦 LEMBRE-SE: CAIXAS DENTRO DE CAIXAS</p>
          <img src={CAIXAS_HIERARQUIA_B64} alt="Hierarquia taxonômica: caixas dentro de caixas"
            style={{display:"block",width:"100%",maxWidth:260,margin:"0 auto",borderRadius:8}}/>
        </div>
      )}
      <OrdemClique onConcluido={(p)=>{addPts(p);setDragOk(true);}}/>
      {dragOk&&<button className="btn-avancar" onClick={()=>setEtapa("quiz")}>📝 PRÓXIMAS PERGUNTAS →</button>}
    </div>
  );
  if(etapa==="dragcustom") return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      <ClassificaFatores onConcluido={(p)=>{addPts(p);setDragOk(true);}}/>
      {dragOk&&<button className="btn-avancar" onClick={()=>setEtapa("quiz")}>📝 Próximo desafio →</button>}
    </div>
  );
  if(etapa==="quiz") return(
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      <QuizItem key={config.quiz[qi].id} q={config.quiz[qi]} versao={versao}
        onResponder={(ok,p)=>{setRespondida(true);addPts(p);}}/>
      {respondida&&(
        <button className="btn-avancar" onClick={avancarQuiz}>
          {qi<config.quiz.length-1?"Próxima questão →":"Concluir fase →"}
        </button>
      )}
    </div>
  );
  if(etapa==="transicao") return(
    <div className="fase-transicao">
      <div className="transicao-badge">{config.badge}</div>
      <div>
        <p className="transicao-sub">Fase {config.num} concluída</p>
        <h2 className="transicao-titulo">{config.tituloBadge}</h2>
      </div>
      <div className="transicao-fala">
        {config.dialogoEncerramento}
        <p style={{marginTop:8,fontSize:13,fontWeight:700,color:"var(--verde-folha)"}}>— Dra. Conceição Ribeiro</p>
      </div>
      <button className="btn-proxima" onClick={()=>onConcluir()}>{config.btnProxima}</button>
    </div>
  );
  return null;
}

